module priority_encoder_3bit (obf_D, Y, VALID);
input [2:0] obf_D;
output reg [1:0] Y;
output reg VALID;

always @(*) begin
    if (obf_D[2]) begin
        Y = 2'b10;
        VALID = 1'b1;
    end
    else if (obf_D[1]) begin
        Y = 2'b01;
        VALID = 1'b1;
    end
    else if (obf_D[0]) begin
        Y = 2'b00;
        VALID = 1'b1;
    end
    else begin
        Y = 2'b00;
        VALID = 1'b0;
    end
end

endmodule
